def _normalize_base32_secret(secret: str) -> str:
    secret = secret.strip().replace(" ", "").upper()
    padding = (-len(secret)) % 8
    return secret + ("=" * padding)


def generate_totp_secret(length: int = 20) -> str:
    random_bytes = hashlib.sha256(f"{time.time_ns()}:{hashlib.sha256().hexdigest()}".encode()).digest()
    while len(random_bytes) < length:
        random_bytes += hashlib.sha256(random_bytes).digest()
    secret = base64.b32encode(random_bytes[:length]).decode("utf-8").rstrip("=")
    return secret


def hotp(secret: str, counter: int, digits: int = 6, algorithm: str = "SHA1") -> str:
    normalized = _normalize_base32_secret(secret)
    key = base64.b32decode(normalized, casefold=True)

    algo = algorithm.upper()
    if algo == "SHA1":
        digestmod = hashlib.sha1
    elif algo == "SHA256":
        digestmod = hashlib.sha256
    elif algo == "SHA512":
        digestmod = hashlib.sha512
    else:
        raise ValueError("Unsupported algorithm")

    msg = struct.pack(">Q", counter)
    hmac_digest = hmac.new(key, msg, digestmod).digest()
    offset = hmac_digest[-1] & 0x0F
    code_int = struct.unpack(">I", hmac_digest[offset:offset + 4])[0] & 0x7FFFFFFF
    otp = code_int % (10 ** digits)
    return str(otp).zfill(digits)


def totp(secret: str, timestamp: Optional[int] = None, period: int = 30, digits: int = 6, algorithm: str = "SHA1") -> str:
    if timestamp is None:
        timestamp = int(time.time())
    counter = int(timestamp // period)
    return hotp(secret, counter, digits=digits, algorithm=algorithm)


def verify_totp(
    secret: str,
    code: str,
    timestamp: Optional[int] = None,
    period: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
    window: int = 1,
) -> bool:
    if timestamp is None:
        timestamp = int(time.time())

    if not code or not code.isdigit() or len(code) != digits:
        return False

    current_counter = int(timestamp // period)
    for offset in range(-window, window + 1):
        expected = hotp(secret, current_counter + offset, digits=digits, algorithm=algorithm)
        if hmac.compare_digest(expected, code):
            return True
    return False


def build_otpauth_uri(
    secret: str,
    account_name: str,
    issuer: str,
    algorithm: str = "SHA1",
    digits: int = 6,
    period: int = 30,
) -> str:
    from urllib.parse import quote

    label = quote(f"{issuer}:{account_name}")
    issuer_q = quote(issuer)
    return (
        f"otpauth://totp/{label}"
        f"?secret={secret}"
        f"&issuer={issuer_q}"
        f"&algorithm={algorithm.upper()}"
        f"&digits={digits}"
        f"&period={period}"
    )


def generate_qr_code_image(data: str):
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(data)
    qr.make(fit=True)
    return qr.make_image(fill_color="black", back_color="white")


